import{_ as t,a,b as o,c as l,d as n}from"./chunks/编辑配置.T0puvWjh.js";import{_ as d,o as r,c as i,a2 as s}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Přidání kanálu Telegram","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/upload/telegram.md","filePath":"cs-CZ/upload/telegram.md","lastUpdated":1781962217000}'),p={name:"cs-CZ/upload/telegram.md"};function c(h,e,k,u,b,v){return r(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="pridani-kanalu-telegram" tabindex="-1">Přidání kanálu Telegram <a class="header-anchor" href="#pridani-kanalu-telegram" aria-label="Permalink to &quot;Přidání kanálu Telegram&quot;">​</a></h1><h2 id="co-potrebujete-pred-zacatkem" tabindex="-1">Co potřebujete před začátkem <a class="header-anchor" href="#co-potrebujete-pred-zacatkem" aria-label="Permalink to &quot;Co potřebujete před začátkem&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Požadavek</th><th>Účel</th></tr></thead><tbody><tr><td>Účet Telegram</td><td>Pro vytvoření bota a úložného kanálu.</td></tr><tr><td><code>@BotFather</code></td><td>Pro vytvoření Telegram bota.</td></tr><tr><td>Telegram kanál</td><td>Cílové místo pro ukládání souborů.</td></tr><tr><td><code>@userinfobot</code></td><td>Pro zjištění <code>Chat ID</code> kanálu.</td></tr></tbody></table><h2 id="kde-ho-pridat" tabindex="-1">Kde ho přidat <a class="header-anchor" href="#kde-ho-pridat" aria-label="Permalink to &quot;Kde ho přidat&quot;">​</a></h2><ol><li>Otevřete Nastavení systému.</li><li>Přejděte do Nastavení nahrávání.</li><li>Klikněte vpravo nahoře na Přidat kanál.</li><li>Vyberte <code>Telegram</code>.</li></ol><h2 id="prehled-poli" tabindex="-1">Přehled polí <a class="header-anchor" href="#prehled-poli" aria-label="Permalink to &quot;Přehled polí&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pole</th><th>Co dělá</th><th>Povinné</th></tr></thead><tbody><tr><td>Název kanálu</td><td>Srozumitelný název, například <code>Telegram Primary</code>.</td><td>Ano</td></tr><tr><td>Aktivní</td><td>Zapíná nebo vypíná kanál.</td><td>Doporučeno</td></tr><tr><td>Bot Token</td><td>Token vašeho Telegram bota.</td><td>Ano</td></tr><tr><td>Session ID (Chat ID)</td><td>ID Telegram kanálu.</td><td>Ano</td></tr><tr><td>Relay Proxy URL (volitelné)</td><td>Použijte jen při nestabilním přístupu k Telegramu. Zadejte celý proxy URL včetně <code>https://</code>.</td><td>Ne</td></tr><tr><td>Poznámka</td><td>Poznámky pro pozdější údržbu.</td><td>Ne</td></tr></tbody></table><h2 id="postup-nastaveni" tabindex="-1">Postup nastavení <a class="header-anchor" href="#postup-nastaveni" aria-label="Permalink to &quot;Postup nastavení&quot;">​</a></h2><h3 id="_1-vytvorte-telegram-bota" tabindex="-1">1. Vytvořte Telegram bota <a class="header-anchor" href="#_1-vytvorte-telegram-bota" aria-label="Permalink to &quot;1. Vytvořte Telegram bota&quot;">​</a></h3><ol><li>Otevřete Telegram a vyhledejte <code>@BotFather</code>.</li><li>Otevřete chat a klikněte na <code>Start</code>.</li><li>Pošlete <code>/newbot</code>.</li><li>Podle pokynů zadejte zobrazovaný název bota.</li><li>Potom zadejte uživatelské jméno bota. Obvykle musí končit na <code>bot</code>.</li><li>Po vytvoření <code>@BotFather</code> vrátí token bota.</li></ol><p>Tento token zadáte v ImgBed jako <code>Bot Token</code>.</p><p><img src="'+t+'" alt="Uložení tokenu bota" loading="lazy"></p><h3 id="_2-vytvorte-kanal" tabindex="-1">2. Vytvořte kanál <a class="header-anchor" href="#_2-vytvorte-kanal" aria-label="Permalink to &quot;2. Vytvořte kanál&quot;">​</a></h3><ol><li>V Telegramu klikněte na Nový kanál.</li><li>Zadejte název kanálu.</li><li>Dokončete vytvoření kanálu.</li></ol><p>Lze použít veřejné i soukromé kanály.</p><p><img src="'+a+'" alt="Vytvoření kanálu" loading="lazy"></p><h3 id="_3-pridejte-bota-do-kanalu" tabindex="-1">3. Přidejte bota do kanálu <a class="header-anchor" href="#_3-pridejte-bota-do-kanalu" aria-label="Permalink to &quot;3. Přidejte bota do kanálu&quot;">​</a></h3><ol><li>Otevřete právě vytvořený kanál.</li><li>Otevřete nastavení kanálu.</li><li>Přidejte člena nebo správce.</li><li>Vyhledejte uživatelské jméno vytvořeného bota.</li><li>Přidejte bota do kanálu.</li></ol><p>Pro nejspolehlivější uploady dejte botovi oprávnění správce.</p><p><img src="'+o+'" alt="Pozvání bota do kanálu" loading="lazy"></p><h3 id="_4-ziskejte-channel-id-pres-user-info-get-id-idbot" tabindex="-1">4. Získejte Channel ID přes User Info - Get ID - IDbot <a class="header-anchor" href="#_4-ziskejte-channel-id-pres-user-info-get-id-idbot" aria-label="Permalink to &quot;4. Získejte Channel ID přes User Info - Get ID - IDbot&quot;">​</a></h3><ol><li>V Telegramu vyhledejte <code>@userinfobot</code>. Zobrazovaný název bývá <code>User Info - Get ID - IDbot</code>.</li><li>Otevřete chat a klikněte na <code>Start</code>.</li><li>V možnostech bota vyberte <code>Channel</code>.</li><li>Ve výběru zprávy zvolte cílový kanál a pošlete ho na <code>@userinfobot</code>.</li><li>Až <code>@userinfobot</code> vrátí výsledek, zkopírujte číslo u <code>Id: -100...</code>.</li></ol><p>Číslo začínající <code>-100</code> je <code>Session ID (Chat ID)</code>, které ImgBed potřebuje.</p><p><img src="'+l+'" alt="Získání Channel ID" loading="lazy"></p><h3 id="_5-vyplnte-telegram-kanal-v-imgbed" tabindex="-1">5. Vyplňte Telegram kanál v ImgBed <a class="header-anchor" href="#_5-vyplnte-telegram-kanal-v-imgbed" aria-label="Permalink to &quot;5. Vyplňte Telegram kanál v ImgBed&quot;">​</a></h3><p>Vraťte se do konfiguračního dialogu a vyplňte:</p><table tabindex="0"><thead><tr><th>Pole UI</th><th>Hodnota</th></tr></thead><tbody><tr><td>Channel Identifier</td><td>Vlastní název kanálu, například <code>TelegramPrimary</code>.</td></tr><tr><td>Aktivní</td><td>Doporučeno.</td></tr><tr><td>Bot Token</td><td>Token od <code>@BotFather</code>.</td></tr><tr><td>Session ID (Chat ID)</td><td>Číslo <code>-100...</code> vrácené <code>@userinfobot</code>.</td></tr><tr><td>Relay Proxy URL (volitelné)</td><td>Jen pokud je potřeba, například <code>https://your-tg-proxy.example.com</code>.</td></tr><tr><td>Poznámka</td><td>Volitelné poznámky.</td></tr></tbody></table><p>Po dokončení klikněte na Uložit.</p><p><img src="'+n+`" alt="Úprava konfigurace" loading="lazy"></p><h2 id="overeni" tabindex="-1">Ověření <a class="header-anchor" href="#overeni" aria-label="Permalink to &quot;Ověření&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kontrola</th><th>Jak ověřit</th></tr></thead><tbody><tr><td>Karta kanálu se zobrazuje</td><td>Po uložení by se v Nastavení nahrávání měla zobrazit karta Telegram.</td></tr><tr><td>Kanál lze zapnout</td><td>Přepínač Aktivní zůstane zapnutý.</td></tr><tr><td>Konfigurace je uložena</td><td>Detail ukazuje uložený Bot Token a Chat ID.</td></tr><tr><td>Upload funguje</td><td>Nahrajte testovací obrázek a ověřte, že se objevil v cílovém kanálu Telegram.</td></tr></tbody></table><h2 id="rychly-checklist" tabindex="-1">Rychlý checklist <a class="header-anchor" href="#rychly-checklist" aria-label="Permalink to &quot;Rychlý checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Vytvořte bota pomocí @BotFather</span></span>
<span class="line"><span>-&gt; Uložte Bot Token</span></span>
<span class="line"><span>-&gt; Vytvořte Telegram kanál</span></span>
<span class="line"><span>-&gt; Přidejte bota do kanálu a dejte mu oprávnění správce</span></span>
<span class="line"><span>-&gt; Vyhledejte @userinfobot a zvolte Channel</span></span>
<span class="line"><span>-&gt; Přepošlete libovolnou zprávu z kanálu do @userinfobot</span></span>
<span class="line"><span>-&gt; Zkopírujte vrácené Id: -100...</span></span>
<span class="line"><span>-&gt; Zadejte Bot Token a Chat ID do ImgBed</span></span>
<span class="line"><span>-&gt; Uložte a nahrajte testovací obrázek</span></span></code></pre></div><h2 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Reference&quot;">​</a></h2><ol><li>Telegram bots: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,35)])])}const P=d(p,[["render",c]]);export{y as __pageData,P as default};
